import { useEffect, useState } from "react";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function Dashboard() {
  const [totalProjects, setTotalProjects] = useState(0);
  const [totalExpenses, setTotalExpenses] = useState(0);

  useEffect(() => {
    const storedProjects =
      JSON.parse(localStorage.getItem("projects")) || [];

    setTotalProjects(storedProjects.length);

    // Calculate total budget
    const totalBudget = storedProjects.reduce(
      (sum, project) => sum + Number(project.budget || 0),
      0
    );

    setTotalExpenses(totalBudget);
  }, []);

  return (
    <div className="flex bg-gray-100 min-h-screen">
      <Sidebar />

      <div className="flex-1 flex flex-col">
        <Topbar />

        <div className="p-8">
          <h1 className="text-3xl font-semibold mb-2">
            Dashboard
          </h1>
          <p className="text-gray-500 mb-8">
            Welcome back! Here's what's happening with your projects.
          </p>

          {/* Stats Cards */}
          <div className="grid grid-cols-3 gap-6 mb-8">
            
            {/* Total Projects */}
            <div className="bg-white p-6 rounded-2xl shadow">
              <h2 className="text-3xl font-bold">
                {totalProjects}
              </h2>
              <p className="text-gray-500">Total Projects</p>
            </div>

            {/* Total Workers (static for now) */}
            <div className="bg-white p-6 rounded-2xl shadow">
              <h2 className="text-3xl font-bold">0</h2>
              <p className="text-gray-500">Total Workers</p>
            </div>

            {/* Total Expenses */}
            <div className="bg-white p-6 rounded-2xl shadow">
              <h2 className="text-3xl font-bold">
                ₹{totalExpenses.toLocaleString()}
              </h2>
              <p className="text-gray-500">Total Expenses</p>
            </div>

          </div>

          {/* Quick Actions */}
          <div className="bg-white p-6 rounded-2xl shadow">
            <h3 className="text-lg font-semibold mb-6">
              Quick Actions
            </h3>

            <div className="grid grid-cols-4 gap-6">
              <div className="border rounded-xl p-4 hover:shadow-md cursor-pointer">
                Add Client
              </div>
              <div className="border rounded-xl p-4 hover:shadow-md cursor-pointer">
                Add Worker
              </div>
              <div className="border rounded-xl p-4 hover:shadow-md cursor-pointer">
                Mark Attendance
              </div>
              <div className="border rounded-xl p-4 hover:shadow-md cursor-pointer">
                Add Expense
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
